(function(G){function escapeHtml(str){const d=document.createElement("div");d.textContent=str==null?"":String(str);return d.innerHTML;}
var currentPriorityAnnouncement=null;var currentAnnouncements=[];var modeProvider=function(){return"normal";};function setModeProvider(fn){if(typeof fn==="function")modeProvider=fn;}
function getMode(){try{return modeProvider()||"normal";}catch(e){return"normal";}}
function isPriorityActive(){return!!currentPriorityAnnouncement;}
function pageType(){return document.body&&document.body.classList.contains("displaybus-body")?"displaybus":"display";}
function hideElementsForPriority(){var pt=pageType();document.getElementById("display-announcements")?.classList.add("hidden");if(pt==="displaybus"){document.querySelector(".displaybus-root")?.classList.add("hidden");return;}
document.querySelector(".display-header")?.classList.add("hidden");document.getElementById("display-grid")?.classList.add("hidden");document.getElementById("display-critical-banner")?.classList.add("hidden");document.getElementById("display-completed-banner")?.classList.add("hidden");document.getElementById("display-waiting")?.classList.add("hidden");}
function showElementsAfterPriority(){var pt=pageType();document.getElementById("display-announcements")?.classList.remove("hidden");if(pt==="displaybus"){document.querySelector(".displaybus-root")?.classList.remove("hidden");return;}
document.querySelector(".display-header")?.classList.remove("hidden");document.getElementById("display-grid")?.classList.remove("hidden");document.getElementById("display-critical-banner")?.classList.remove("hidden");document.getElementById("display-completed-banner")?.classList.remove("hidden");document.getElementById("display-waiting")?.classList.add("hidden");}
function showPriorityAnnouncement(ann){var overlay=document.getElementById("display-priority-announcement");if(!overlay)return;overlay.classList.remove("hidden");overlay.innerHTML='<div class="display-priority-content">'+'<h1 class="display-priority-title">'+
escapeHtml(ann.title)+"</h1>"+
(ann.content?'<div class="display-priority-body">'+escapeHtml(ann.content)+"</div>":"")+
(ann.extra_info?'<div class="display-priority-extra">'+escapeHtml(ann.extra_info)+"</div>":"")+"</div>";hideElementsForPriority();}
function hidePriorityAnnouncement(){var overlay=document.getElementById("display-priority-announcement");if(overlay)overlay.classList.add("hidden");showElementsAfterPriority();}
function hidePriorityAnnouncementWithAnimation(){var overlay=document.getElementById("display-priority-announcement");if(!overlay)return;overlay.classList.add("display-priority-exit");setTimeout(function(){overlay.classList.remove("display-priority-exit");hidePriorityAnnouncement();},400);}
function fetchPriorityAnnouncement(){return fetch("/api/display/priority-announcement").then(function(res){return res.json();}).then(function(data){if(data&&data.id){currentPriorityAnnouncement=data;showPriorityAnnouncement(data);}else{if(currentPriorityAnnouncement)hidePriorityAnnouncementWithAnimation();currentPriorityAnnouncement=null;}}).catch(function(){if(currentPriorityAnnouncement)hidePriorityAnnouncementWithAnimation();currentPriorityAnnouncement=null;});}
function updatePaddingForAnnouncements(){var annContainer=document.getElementById("display-announcements");if(!annContainer)return;var h=annContainer.offsetHeight||0;var pad=h>0?h+24:100;if(pageType()==="displaybus"){var main=document.getElementById("displaybus-main");if(main)main.style.paddingBottom=pad+"px";}else{var grid=document.getElementById("display-grid");if(grid)grid.style.paddingBottom=pad+"px";}}
function updateAnnouncements(announcements){var annContainer=document.getElementById("display-announcements");if(!annContainer)return;var currentIds=new Set(currentAnnouncements.map(function(a){return a.id;}));var newIds=new Set(announcements.map(function(a){return a.id;}));announcements.forEach(function(a){if(!document.getElementById("ann-"+a.id)){var el=document.createElement("div");el.id="ann-"+a.id;el.className="display-announcement display-ann-"+a.style+" display-ann-enter";el.innerHTML='<div class="display-ann-icon">'+
(a.style==="urgent"?"🚨":a.style==="warning"?"⚠️":a.style==="success"?"✅":"ℹ️")+"</div>"+'<div class="display-ann-text"><strong>'+
escapeHtml(a.title)+"</strong>"+
(a.content?"<span>"+escapeHtml(a.content)+"</span>":"")+"</div>";annContainer.appendChild(el);requestAnimationFrame(function(){requestAnimationFrame(function(){el.classList.remove("display-ann-enter");});});}});currentIds.forEach(function(id){if(!newIds.has(id)){var el=document.getElementById("ann-"+id);if(el){el.classList.add("display-ann-exit");setTimeout(function(){el.remove();},500);}}});currentAnnouncements=announcements;requestAnimationFrame(function(){updatePaddingForAnnouncements();});}
function fetchAnnouncements(){if(getMode()!=="normal")return Promise.resolve();return fetch("/api/display/announcements").then(function(res){return res.json();}).then(function(data){updateAnnouncements(data);}).catch(function(e){console.error(e);});}
G.DisplayAnnouncements={setModeProvider:setModeProvider,isPriorityActive:isPriorityActive,fetchPriorityAnnouncement:fetchPriorityAnnouncement,fetchAnnouncements:fetchAnnouncements,hidePriorityAnnouncementWithAnimation:hidePriorityAnnouncementWithAnimation,hidePriorityAnnouncement:hidePriorityAnnouncement,escapeHtml:escapeHtml,};})(typeof window!=="undefined"?window:globalThis);